import{_ as l,o as e,c as a,ag as o}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"🏛️ 远程会话与安全审计平台：架构设计","description":"","frontmatter":{"order":1},"headers":[],"relativePath":"development/audit-platform/architecture.md","filePath":"development/audit-platform/architecture.md","lastUpdated":1774465297000}'),i={name:"development/audit-platform/architecture.md"};function r(n,t,s,c,d,p){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="🏛️-远程会话与安全审计平台-架构设计" tabindex="-1">🏛️ 远程会话与安全审计平台：架构设计 <a class="header-anchor" href="#🏛️-远程会话与安全审计平台-架构设计" aria-label="Permalink to &quot;🏛️ 远程会话与安全审计平台：架构设计&quot;">​</a></h1><p>本系统旨在解决企业内网运维过程中的权限管控混乱、高危操作无法溯源等痛点。通过构建统一的远程访问网关，实现对 SSH、RDP 等协议的细粒度会话管理与全量安全审计。</p><h2 id="📊-系统核心架构图" tabindex="-1">📊 系统核心架构图 <a class="header-anchor" href="#📊-系统核心架构图" aria-label="Permalink to &quot;📊 系统核心架构图&quot;">​</a></h2><p>系统整体采用<strong>前后端分离 + 核心代理网关</strong>的架构模式，自上而下划分为四个逻辑层：</p><ol><li><strong>Web 表现层 (Frontend)</strong><ul><li>提供管理员控制台与用户视图。</li><li>负责资产展示、策略配置、以及在线 Web 终端（Web Terminal）的直连访问。</li></ul></li><li><strong>业务控制层 (Control Plane)</strong><ul><li>处理用户认证（鉴权与 SSO 接入）。</li><li>管理资产授权策略（RBAC 模型）。</li><li>调度审计任务与日志下发。</li></ul></li><li><strong>协议代理网关 (Data Plane / Proxy Gateway)</strong><ul><li><strong>这是系统的核心引擎。</strong> 负责拦截、解析并转发客户端与目标服务器之间的底层协议流量（如 SSH, RDP, Telnet）。</li><li>实时阻断触发安全规则的高危命令。</li></ul></li><li><strong>数据与审计存储层 (Storage)</strong><ul><li><strong>关系型数据：</strong> 存储用户、资产、授权关系。</li><li><strong>审计录像：</strong> 采用高效的结构化格式存储终端录像（如 asciinema 格式），以便于极速回放和全文命令检索。</li></ul></li></ol><h2 id="🛡️-核心业务流转-一次安全的-ssh-登录" tabindex="-1">🛡️ 核心业务流转：一次安全的 SSH 登录 <a class="header-anchor" href="#🛡️-核心业务流转-一次安全的-ssh-登录" aria-label="Permalink to &quot;🛡️ 核心业务流转：一次安全的 SSH 登录&quot;">​</a></h2><p>为了实现无缝且安全的审计，系统设计了如下会话流转机制：</p><ol><li>用户登录 Web 控制台，获取被授权的资产列表。</li><li>用户点击“连接”，Web 端向控制面申请一个临时会话 Token。</li><li>控制面将 Token 与目标资产凭证下发给 <strong>协议代理网关</strong>。</li><li>代理网关利用 WebSocket 与浏览器建立连接，同时在后端使用真实凭证发起向目标服务器的 SSH 连接。</li><li><strong>审计开启：</strong> 代理网关在中间实时双向抓取 I/O 数据流，异步写入审计存储模块，实现“所见即所录”。</li></ol><div class="info custom-block"><p class="custom-block-title">🚀 持续迭代</p><p>本架构文档将随着项目的推进持续更新。后续将重点攻克高并发下的网关性能瓶颈以及 RDP 协议的图像压缩解析难题。</p></div>',9)])])}const h=l(i,[["render",r]]);export{g as __pageData,h as default};
